SELECT COUNT(*)
  FROM com.tn_oprtr
 WHERE icao_desig = #{icaoDesig}
   AND oprtr_id  != #{oprtrId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE com.tn_oprtr
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE oprtr_id = #{oprtrId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
